/**
 * Operational Detail Layer
 *
 * Konva-based detailed PM card layer for operational view (zoom levels 12-16).
 * Renders individual PM cards with comprehensive information including:
 * - Train identification with fleet colors
 * - PM details (code, description, dates, status)
 * - Track and depot assignment
 * - Material availability indicators
 * - Compliance window visualization
 * - Action indicators (lock, edit, history)
 *
 * Features:
 * - Card-based layout with vertical train stacking
 * - Daily timeline granularity (4-week view)
 * - Interactive hover and click handlers
 * - Status-based color coding
 * - Material availability badges
 *
 * @see specs/006-user-interface.md Section 6.3.4
 */

import { useRef } from 'react';
import { Stage, Layer, Rect, Text, Line, Group } from 'react-konva';
import type { Stage as StageType } from 'konva/lib/Stage';

import type { OperationalPmBlock, OperationalCanvasData, MaterialStatus } from './types';
import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS, MATERIAL_STATUS_COLORS } from '../../theme/colors';

// =============================================================================
// Constants
// =============================================================================

/** Layout constants for operational cards */
const LAYOUT = {
  HEADER_HEIGHT: 64,
  TRAIN_LABEL_WIDTH: 140,
  CARD_WIDTH: 280,
  CARD_HEIGHT: 180,
  CARD_MARGIN: 12,
  CARD_PADDING: 12,
  DAY_WIDTH: 48,
  ROW_HEIGHT: 200,
  MIN_CARD_WIDTH: 200,
  GRID_LINE_COLOR: '#e2e8f0',
  HEADER_BG: '#f8fafc',
  CARD_BG: '#ffffff',
  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
};

/** PM status to color mapping */
function getPmStatusColor(status: string): string {
  switch (status) {
    case 'SCHEDULED':
      return PM_STATUS_COLORS.scheduled;
    case 'IN_PROGRESS':
      return PM_STATUS_COLORS.inProgress;
    case 'COMPLETED':
      return PM_STATUS_COLORS.completed;
    case 'CANCELLED':
      return PM_STATUS_COLORS.cancelled;
    case 'DEFERRED':
      return PM_STATUS_COLORS.deferred;
    default:
      return PM_STATUS_COLORS.scheduled;
  }
}

/** Material status to color mapping */
function getMaterialStatusColor(status: MaterialStatus): string {
  return MATERIAL_STATUS_COLORS[status] ?? MATERIAL_STATUS_COLORS.AVAILABLE;
}

/** Material status to icon mapping */
function getMaterialStatusIcon(status: MaterialStatus): string {
  switch (status) {
    case 'AVAILABLE':
      return '✓';
    case 'LOW_STOCK':
      return '⚠';
    case 'UNAVAILABLE':
      return '✗';
    case 'ARRIVING':
      return '⏳';
    default:
      return '?';
  }
}

// =============================================================================
// Types
// =============================================================================

export interface OperationalDetailLayerProps {
  data: OperationalCanvasData | null;
  fromDate: Date;
  toDate: Date;
  width: number;
  height: number;
  selectedPmIds?: string[];
  onPmClick?: (pmId: string) => void;
  onPmHover?: (pm: OperationalPmBlock | null) => void;
  onPmEdit?: (pmId: string) => void;
  onPmLock?: (pmId: string) => void;
  showGrid?: boolean;
}

interface DayData {
  date: Date;
  dateStr: string;
  dayOfWeek: number;
  isWeekStart: boolean;
  isToday: boolean;
  label: string;
}

interface WeekData {
  weekStart: Date;
  weekNum: number;
  month: string;
  daysInWeek: number;
}

// =============================================================================
// Pure Utility Functions
// =============================================================================

function getDays(fromDate: Date, toDate: Date): DayData[] {
  const days: DayData[] = [];
  const current = new Date(fromDate);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

  while (current <= toDate) {
    const dayOfWeek = current.getDay();
    days.push({
      date: new Date(current),
      dateStr: current.toISOString().split('T')[0],
      dayOfWeek,
      isWeekStart: dayOfWeek === 0,
      isToday: current.getTime() === today.getTime(),
      label: `${dayNames[dayOfWeek]} ${current.getDate()}`,
    });
    current.setDate(current.getDate() + 1);
  }
  return days;
}

function getWeeks(days: DayData[]): WeekData[] {
  const weeks: WeekData[] = [];
  let currentWeek: WeekData | null = null;
  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

  for (const day of days) {
    if (day.isWeekStart || currentWeek === null) {
      if (currentWeek) {
        weeks.push(currentWeek);
      }
      const weekNum = getWeekNumber(day.date);
      currentWeek = {
        weekStart: day.date,
        weekNum,
        month: monthNames[day.date.getMonth()],
        daysInWeek: 1,
      };
    } else {
      currentWeek.daysInWeek++;
    }
  }
  if (currentWeek) {
    weeks.push(currentWeek);
  }
  return weeks;
}

function getWeekNumber(date: Date): number {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  return Math.ceil(((d.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);
}

function dateDiffDays(a: Date, b: Date): number {
  return Math.floor((a.getTime() - b.getTime()) / (1000 * 60 * 60 * 24));
}

function parseDate(dateStr: string): Date {
  return new Date(dateStr + 'T00:00:00');
}

function formatDateRange(startDate: string, endDate: string): string {
  const start = new Date(startDate);
  const end = new Date(endDate);
  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

  if (startDate === endDate) {
    return `${monthNames[start.getMonth()]} ${start.getDate()}`;
  }

  if (start.getMonth() === end.getMonth()) {
    return `${monthNames[start.getMonth()]} ${start.getDate()}-${end.getDate()}`;
  }

  return `${monthNames[start.getMonth()]} ${start.getDate()} - ${monthNames[end.getMonth()]} ${end.getDate()}`;
}

function buildTrainGroups(pmBlocks: OperationalPmBlock[]): Map<string, OperationalPmBlock[]> {
  const groups = new Map<string, OperationalPmBlock[]>();

  for (const pm of pmBlocks) {
    if (!groups.has(pm.trainId)) {
      groups.set(pm.trainId, []);
    }
    groups.get(pm.trainId)!.push(pm);
  }

  return groups;
}

// =============================================================================
// Sub-Components
// =============================================================================

interface TimelineHeaderProps {
  days: DayData[];
  weeks: WeekData[];
  offsetX: number;
}

function TimelineHeader({ days, weeks, offsetX }: TimelineHeaderProps) {
  return (
    <Group x={offsetX} y={0}>
      {/* Week/Month row */}
      <Rect
        x={0}
        y={0}
        width={days.length * LAYOUT.DAY_WIDTH}
        height={LAYOUT.HEADER_HEIGHT / 2}
        fill={LAYOUT.HEADER_BG}
      />
      {weeks.map((week, i) => {
        const x = days.findIndex((d) => d.date.getTime() === week.weekStart.getTime()) * LAYOUT.DAY_WIDTH;
        const width = week.daysInWeek * LAYOUT.DAY_WIDTH;
        return (
          <Group key={i} x={x} y={0}>
            <Rect
              width={width}
              height={LAYOUT.HEADER_HEIGHT / 2}
              stroke={LAYOUT.GRID_LINE_COLOR}
              strokeWidth={1}
            />
            <Text
              x={8}
              y={8}
              text={`${week.month} - Week ${week.weekNum}`}
              fontSize={12}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#475569"
              fontStyle="bold"
            />
          </Group>
        );
      })}

      {/* Day row */}
      {days.map((day, i) => (
        <Group key={day.dateStr} x={i * LAYOUT.DAY_WIDTH} y={LAYOUT.HEADER_HEIGHT / 2}>
          <Rect
            width={LAYOUT.DAY_WIDTH}
            height={LAYOUT.HEADER_HEIGHT / 2}
            fill={day.isToday ? '#dbeafe' : day.dayOfWeek === 0 || day.dayOfWeek === 6 ? '#f1f5f9' : LAYOUT.HEADER_BG}
            stroke={LAYOUT.GRID_LINE_COLOR}
            strokeWidth={0.5}
          />
          <Text
            x={4}
            y={8}
            text={day.label}
            fontSize={10}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill={day.isToday ? '#2563eb' : '#64748b'}
            fontStyle={day.isToday ? 'bold' : 'normal'}
          />
        </Group>
      ))}
    </Group>
  );
}

interface TrainLabelsPanelProps {
  trainGroups: Map<string, OperationalPmBlock[]>;
  trainOrder: string[];
}

function TrainLabelsPanel({ trainGroups, trainOrder }: TrainLabelsPanelProps) {
  return (
    <Group x={0} y={LAYOUT.HEADER_HEIGHT}>
      <Rect
        width={LAYOUT.TRAIN_LABEL_WIDTH}
        height={trainOrder.length * LAYOUT.ROW_HEIGHT}
        fill="#ffffff"
      />
      {trainOrder.map((trainId, i) => {
        const pms = trainGroups.get(trainId) || [];
        const firstPm = pms[0];
        if (!firstPm) return null;

        const fleetCode = firstPm.fleetCode || 'KS';
        const fleetColor = FLEET_COLORS[fleetCode as keyof typeof FLEET_COLORS] || FLEET_COLORS.KS;

        return (
          <Group key={trainId} y={i * LAYOUT.ROW_HEIGHT}>
            <Rect
              width={LAYOUT.TRAIN_LABEL_WIDTH}
              height={LAYOUT.ROW_HEIGHT}
              stroke={LAYOUT.GRID_LINE_COLOR}
              strokeWidth={0.5}
              fill="#fafafa"
            />
            {/* Fleet color bar */}
            <Rect
              x={6}
              y={12}
              width={6}
              height={LAYOUT.ROW_HEIGHT - 24}
              fill={fleetColor}
              cornerRadius={3}
            />
            {/* Train number */}
            <Text
              x={18}
              y={16}
              text={firstPm.trainNumber}
              fontSize={14}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#1e293b"
              fontStyle="bold"
            />
            {/* Fleet code */}
            <Text
              x={18}
              y={34}
              text={fleetCode}
              fontSize={11}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#64748b"
            />
            {/* PM count */}
            <Text
              x={18}
              y={52}
              text={`${pms.length} PM${pms.length !== 1 ? 's' : ''}`}
              fontSize={10}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#94a3b8"
            />
          </Group>
        );
      })}
    </Group>
  );
}

interface GridLayerProps {
  days: DayData[];
  rowCount: number;
  offsetX: number;
}

function GridLayer({ days, rowCount, offsetX }: GridLayerProps) {
  const todayIndex = days.findIndex((d) => d.isToday);

  return (
    <Group x={offsetX} y={LAYOUT.HEADER_HEIGHT}>
      {/* Row backgrounds */}
      {Array.from({ length: rowCount }).map((_, i) => (
        <Rect
          key={i}
          y={i * LAYOUT.ROW_HEIGHT}
          width={days.length * LAYOUT.DAY_WIDTH}
          height={LAYOUT.ROW_HEIGHT}
          fill={i % 2 === 0 ? '#ffffff' : '#fafafa'}
          stroke={LAYOUT.GRID_LINE_COLOR}
          strokeWidth={0.5}
        />
      ))}

      {/* Today highlight column */}
      {todayIndex >= 0 && (
        <Rect
          x={todayIndex * LAYOUT.DAY_WIDTH}
          y={0}
          width={LAYOUT.DAY_WIDTH}
          height={rowCount * LAYOUT.ROW_HEIGHT}
          fill="rgba(37, 99, 235, 0.05)"
        />
      )}

      {/* Week separator lines */}
      {days.filter((d) => d.isWeekStart).map((day) => {
        const x = days.indexOf(day) * LAYOUT.DAY_WIDTH;
        return (
          <Line
            key={`week-${day.dateStr}`}
            points={[x, 0, x, rowCount * LAYOUT.ROW_HEIGHT]}
            stroke="#cbd5e1"
            strokeWidth={1}
          />
        );
      })}

      {/* Today indicator line */}
      {todayIndex >= 0 && (
        <Line
          points={[
            todayIndex * LAYOUT.DAY_WIDTH + LAYOUT.DAY_WIDTH / 2,
            0,
            todayIndex * LAYOUT.DAY_WIDTH + LAYOUT.DAY_WIDTH / 2,
            rowCount * LAYOUT.ROW_HEIGHT,
          ]}
          stroke="#2563eb"
          strokeWidth={2}
          dash={[6, 4]}
        />
      )}
    </Group>
  );
}

interface PmCardProps {
  pm: OperationalPmBlock;
  x: number;
  y: number;
  width: number;
  isSelected: boolean;
  onHover?: (pm: OperationalPmBlock | null) => void;
  onClick?: (pmId: string) => void;
  onEdit?: (pmId: string) => void;
  onLock?: (pmId: string) => void;
}

function PmCard({
  pm,
  x,
  y,
  width,
  isSelected,
  onHover,
  onClick,
}: PmCardProps) {
  const statusColor = pm.displayColor || getPmStatusColor(pm.status);
  const cardWidth = Math.max(width, LAYOUT.MIN_CARD_WIDTH);
  const cardHeight = LAYOUT.CARD_HEIGHT;

  // Calculate compliance window progress
  const constraintStart = parseDate(pm.constraintStart);
  const constraintEnd = parseDate(pm.constraintEnd);
  const targetDate = parseDate(pm.targetDate);
  const totalWindow = dateDiffDays(constraintEnd, constraintStart) || 1;
  const positionInWindow = dateDiffDays(targetDate, constraintStart);
  const progressPct = Math.min(100, Math.max(0, (positionInWindow / totalWindow) * 100));

  // Determine compliance status
  let complianceColor: string = CONSTRAINT_COLORS.ok;
  if (progressPct > 90) {
    complianceColor = CONSTRAINT_COLORS.hardViolation;
  } else if (progressPct > 70) {
    complianceColor = CONSTRAINT_COLORS.approaching;
  }

  return (
    <Group
      x={x}
      y={y}
      onMouseEnter={() => onHover?.(pm)}
      onMouseLeave={() => onHover?.(null)}
      onClick={() => onClick?.(pm.pmId)}
    >
      {/* Selection highlight */}
      {isSelected && (
        <Rect
          x={-3}
          y={-3}
          width={cardWidth + 6}
          height={cardHeight + 6}
          fill="transparent"
          stroke="#3b82f6"
          strokeWidth={2}
          cornerRadius={10}
        />
      )}

      {/* Card background */}
      <Rect
        width={cardWidth}
        height={cardHeight}
        fill={LAYOUT.CARD_BG}
        stroke={isSelected ? '#2563eb' : '#e2e8f0'}
        strokeWidth={1}
        cornerRadius={8}
        shadowColor="#000"
        shadowBlur={4}
        shadowOpacity={0.08}
        shadowOffsetY={2}
      />

      {/* Status color bar */}
      <Rect
        x={0}
        y={0}
        width={8}
        height={cardHeight}
        fill={statusColor}
        cornerRadius={[8, 0, 0, 8]}
      />

      {/* Header section */}
      <Group x={LAYOUT.CARD_PADDING + 4} y={LAYOUT.CARD_PADDING}>
        {/* PM Code */}
        <Text
          text={pm.pmCode}
          fontSize={14}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#1e293b"
          fontStyle="bold"
        />

        {/* Train number */}
        <Text
          y={18}
          text={pm.trainNumber}
          fontSize={11}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#64748b"
        />

        {/* Lock indicator */}
        {pm.isLocked && (
          <Text
            x={cardWidth - 40}
            y={0}
            text="🔒"
            fontSize={14}
          />
        )}

        {/* Status badge */}
        <Group x={cardWidth - 90} y={0}>
          <Rect
            width={60}
            height={20}
            fill={statusColor}
            cornerRadius={4}
            opacity={0.2}
          />
          <Text
            x={4}
            y={4}
            text={pm.status.replace('_', ' ')}
            fontSize={9}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill={statusColor}
            fontStyle="bold"
          />
        </Group>
      </Group>

      {/* Date and details section */}
      <Group x={LAYOUT.CARD_PADDING + 4} y={48}>
        {/* Date range */}
        <Text
          text={formatDateRange(pm.targetDate, pm.endDate)}
          fontSize={11}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#475569"
        />

        {/* Duration */}
        <Text
          x={100}
          text={`${pm.durationDays}d`}
          fontSize={11}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#64748b"
        />

        {/* Hours */}
        {pm.estimatedHours && (
          <Text
            x={130}
            text={`${pm.estimatedHours}h`}
            fontSize={11}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill="#64748b"
          />
        )}

        {/* Track and depot */}
        <Text
          y={16}
          text={[pm.depotCode, pm.trackNumber].filter(Boolean).join(' • ') || 'Unassigned'}
          fontSize={10}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#94a3b8"
        />

        {/* Shift */}
        {pm.assignedShift && (
          <Text
            y={30}
            text={`Shift: ${pm.assignedShift}`}
            fontSize={10}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill="#94a3b8"
          />
        )}
      </Group>

      {/* Compliance window visualization */}
      <Group x={LAYOUT.CARD_PADDING + 4} y={100}>
        <Text
          text="Compliance Window"
          fontSize={9}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#94a3b8"
        />

        {/* Progress bar background */}
        <Rect
          y={14}
          width={cardWidth - LAYOUT.CARD_PADDING * 2 - 8}
          height={8}
          fill="#f1f5f9"
          cornerRadius={4}
        />

        {/* Progress bar fill */}
        <Rect
          y={14}
          width={(cardWidth - LAYOUT.CARD_PADDING * 2 - 8) * (progressPct / 100)}
          height={8}
          fill={complianceColor}
          cornerRadius={4}
        />

        {/* Target date marker */}
        <Line
          points={[
            (cardWidth - LAYOUT.CARD_PADDING * 2 - 8) * (progressPct / 100),
            12,
            (cardWidth - LAYOUT.CARD_PADDING * 2 - 8) * (progressPct / 100),
            24,
          ]}
          stroke="#1e293b"
          strokeWidth={2}
        />

        {/* Date labels */}
        <Text
          y={26}
          text={pm.constraintStart.slice(5)}
          fontSize={8}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#94a3b8"
        />
        <Text
          x={cardWidth - LAYOUT.CARD_PADDING * 2 - 40}
          y={26}
          text={pm.constraintEnd.slice(5)}
          fontSize={8}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#94a3b8"
        />
      </Group>

      {/* Materials section */}
      <Group x={LAYOUT.CARD_PADDING + 4} y={140}>
        <Text
          text="Materials"
          fontSize={9}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="#94a3b8"
        />

        {pm.materials.length > 0 ? (
          pm.materials.slice(0, 2).map((material, idx) => (
            <Group key={material.materialId} y={14 + idx * 14}>
              <Text
                text={getMaterialStatusIcon(material.status)}
                fontSize={10}
                fill={getMaterialStatusColor(material.status)}
              />
              <Text
                x={14}
                text={`${material.materialName.slice(0, 20)}${material.materialName.length > 20 ? '...' : ''}`}
                fontSize={9}
                fontFamily={LAYOUT.FONT_FAMILY}
                fill="#64748b"
              />
              <Text
                x={cardWidth - 60}
                text={`${material.quantityAvailable}/${material.quantityRequired}`}
                fontSize={9}
                fontFamily={LAYOUT.FONT_FAMILY}
                fill={getMaterialStatusColor(material.status)}
              />
            </Group>
          ))
        ) : (
          <Text
            y={14}
            text="No materials required"
            fontSize={9}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill="#94a3b8"
            fontStyle="italic"
          />
        )}
      </Group>
    </Group>
  );
}

// =============================================================================
// Main Component
// =============================================================================

export function OperationalDetailLayer({
  data,
  fromDate,
  toDate,
  width,
  height,
  selectedPmIds = [],
  onPmClick,
  onPmHover,
  showGrid = true,
}: OperationalDetailLayerProps) {
  const stageRef = useRef<StageType>(null);

  if (!data) {
    return null;
  }

  // Compute derived data
  const days = getDays(fromDate, toDate);
  const weeks = getWeeks(days);
  const trainGroups = buildTrainGroups(data.pmBlocks);
  const trainOrder = Array.from(trainGroups.keys());
  const selectedSet = new Set(selectedPmIds);

  const gridOffsetX = LAYOUT.TRAIN_LABEL_WIDTH;
  const contentWidth = days.length * LAYOUT.DAY_WIDTH + gridOffsetX;
  const contentHeight = trainOrder.length * LAYOUT.ROW_HEIGHT + LAYOUT.HEADER_HEIGHT;

  return (
    <Stage
      ref={stageRef}
      width={width}
      height={height}
      style={{ backgroundColor: '#f8fafc' }}
    >
      {/* Background layer */}
      <Layer>
        <Rect width={contentWidth} height={contentHeight} fill="#ffffff" />
      </Layer>

      {/* Grid layer */}
      {showGrid && (
        <Layer>
          <GridLayer days={days} rowCount={trainOrder.length} offsetX={gridOffsetX} />
        </Layer>
      )}

      {/* PM Cards layer */}
      <Layer>
        <Group x={gridOffsetX} y={LAYOUT.HEADER_HEIGHT}>
          {trainOrder.map((trainId, trainIndex) => {
            const pms = trainGroups.get(trainId) || [];

            return pms.map((pm) => {
              const pmDate = parseDate(pm.targetDate);
              const dayOffset = dateDiffDays(pmDate, fromDate);
              if (dayOffset < 0 || dayOffset >= days.length) return null;

              const x = dayOffset * LAYOUT.DAY_WIDTH + LAYOUT.CARD_MARGIN;
              const y = trainIndex * LAYOUT.ROW_HEIGHT + LAYOUT.CARD_MARGIN;
              const cardWidth = pm.durationDays * LAYOUT.DAY_WIDTH - LAYOUT.CARD_MARGIN * 2;

              return (
                <PmCard
                  key={pm.pmId}
                  pm={pm}
                  x={x}
                  y={y}
                  width={cardWidth}
                  isSelected={selectedSet.has(pm.pmId)}
                  onHover={onPmHover}
                  onClick={onPmClick}
                />
              );
            });
          })}
        </Group>
      </Layer>

      {/* Timeline header layer (on top) */}
      <Layer>
        <TimelineHeader days={days} weeks={weeks} offsetX={gridOffsetX} />
      </Layer>

      {/* Train labels layer (fixed left) */}
      <Layer>
        <TrainLabelsPanel trainGroups={trainGroups} trainOrder={trainOrder} />
      </Layer>
    </Stage>
  );
}

export default OperationalDetailLayer;

