   459→            )}
   460→          </div>
   461→
   462→          {/* Legend */}
   463→          <div
   464→            style={{
   465→              display: 'flex',
   466→              justifyContent: 'center',
   467→              gap: 16,
   468→              padding: '8px 16px',
   469→              borderTop: '1px solid var(--pt-divider-black)',
   470→              fontSize: 10,
   471→            }}
   472→          >
   473→            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
   474→              <div style={{ width: 8, height: 8, borderRadius: 2, backgroundColor: STATUS_COLORS.OVERLOADED }} />
   475→              <span>Overloaded</span>
   476→            </div>
   477→            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
   478→              <div style={{ width: 8, height: 8, borderRadius: 2, backgroundColor: STATUS_COLORS.OPTIMAL }} />
   479→              <span>Optimal</span>
   480→            </div>
   481→            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
   482→              <div style={{ width: 8, height: 8, borderRadius: 2, backgroundColor: STATUS_COLORS.UNDERUTILIZED }} />
   483→              <span>Under</span>
   484→            </div>
   485→          </div>
   486→        </>
   487→      )}
   488→    </Card>
   489→  );
   490→}
