     1→/**
     2→ * BowWaveIndicator Component
     3→ *
     4→ * Displays bow-wave risk status for maintenance clustering visualization.
     5→ * Bow-wave occurs when PM work accumulates in later periods, causing
     6→ * operational overload and potential service disruptions.
     7→ *
     8→ * This component shows:
     9→ * - Current risk level (LOW/MEDIUM/HIGH/CRITICAL)
    10→ * - Risk score (0-100%)
    11→ * - Peak periods requiring attention
    12→ * - Actionable recommendations
    13→ *
    14→ * @see specs/006-user-interface.md Section 6.5 - Overlay Panels
    15→ * @see specs/004-domain-services.md Section 4.6 - Strategic Planner (bow-wave detection)
    16→ */
    17→
    18→import {
    19→  Tag,
    20→  Intent,
    21→  Popover,
    22→  Menu,
    23→  MenuItem,
    24→  MenuDivider,
    25→  ProgressBar,
    26→  Tooltip,
    27→  Spinner,
    28→  Classes,
    29→} from '@blueprintjs/core';
    30→
    31→import { useOverlay } from '../store';
    32→import type { OverlaySliceState } from '../store/slices/overlay';
    33→import {
    34→  selectBowWaveRiskDisplay,
    35→  selectBowWavePeakPeriods,
    36→  selectBowWaveHighPriorityRecommendations,
    37→  selectBowWaveSummary,
    38→  loadBowWaveOverlayData,
    39→  type BowWaveRiskLevel,
    40→  type BowWavePeakPeriod,
    41→  type BowWaveRecommendation,
    42→} from '../store/slices/overlay';
    43→
    44→// =============================================================================
    45→// Types
    46→// =============================================================================
    47→
    48→interface BowWaveIndicatorProps {
    49→  /** Show compact version for toolbar */
    50→  compact?: boolean;
    51→  /** Fleet ID to filter by */
    52→  fleetId?: string;
    53→  /** Plan ID to show specific plan's bow-wave analysis */
    54→  planId?: string;
    55→  /** Custom class name */
    56→  className?: string;
    57→}
    58→
    59→// =============================================================================
    60→// Color Mapping
    61→// =============================================================================
    62→
    63→const RISK_INTENT_MAP: Record<BowWaveRiskLevel, Intent> = {
    64→  LOW: 'success',
    65→  MEDIUM: 'warning',
    66→  HIGH: 'warning',
    67→  CRITICAL: 'danger',
    68→};
    69→
    70→const RISK_ICON_MAP: Record<BowWaveRiskLevel, 'tick-circle' | 'warning-sign' | 'error'> = {
    71→  LOW: 'tick-circle',
    72→  MEDIUM: 'warning-sign',
    73→  HIGH: 'warning-sign',
    74→  CRITICAL: 'error',
    75→};
    76→
    77→const RECOMMENDATION_ICON_MAP: Record<BowWaveRecommendation['type'], 'arrow-left' | 'arrow-right' | 'people' | 'horizontal-distribution'> = {
    78→  ADVANCE_PM: 'arrow-left',
    79→  DEFER_PM: 'arrow-right',
    80→  ADD_CAPACITY: 'people',
    81→  SPREAD_WORKLOAD: 'horizontal-distribution',
    82→};
    83→
    84→// =============================================================================
    85→// Helper Components
    86→// =============================================================================
    87→
    88→function RiskProgressBar({
    89→  riskScore,
    90→  riskLevel,
    91→}: {
    92→  riskScore: number;
    93→  riskLevel: BowWaveRiskLevel;
    94→}) {
    95→  const intent = RISK_INTENT_MAP[riskLevel];
    96→
    97→  return (
    98→    <div style={{ marginTop: 8 }}>
    99→      <div
   100→        style={{
   101→          display: 'flex',
   102→          justifyContent: 'space-between',
   103→          marginBottom: 4,
   104→          fontSize: 11,
   105→        }}
   106→      >
   107→        <span className={Classes.TEXT_MUTED}>Risk Score</span>
   108→        <span style={{ fontWeight: 500 }}>{Math.round(riskScore * 100)}%</span>
   109→      </div>
   110→      <ProgressBar
   111→        value={riskScore}
   112→        intent={intent}
   113→        stripes={riskLevel === 'CRITICAL'}
   114→        animate={riskLevel === 'CRITICAL'}
   115→      />
   116→    </div>
   117→  );
   118→}
   119→
   120→function PeakPeriodItem({ period }: { period: BowWavePeakPeriod }) {
   121→  const intent = RISK_INTENT_MAP[period.riskLevel];
   122→
   123→  return (
   124→    <MenuItem
   125→      icon="calendar"
   126→      text={`${period.startQuarter} - ${period.endQuarter}`}
   127→      labelElement={
   128→        <Tag minimal intent={intent}>
   129→          {period.peakLoad} PMs/mo
   130→        </Tag>
   131→      }
   132→    />
   133→  );
   134→}
   135→
   136→function RecommendationItem({ rec }: { rec: BowWaveRecommendation }) {
   137→  const priorityIntent: Intent =
   138→    rec.priority === 'HIGH' ? 'danger' : rec.priority === 'MEDIUM' ? 'warning' : 'none';
   139→
   140→  return (
   141→    <MenuItem
   142→      icon={RECOMMENDATION_ICON_MAP[rec.type]}
   143→      text={rec.description}
   144→      labelElement={
   145→        <Tag minimal intent={priorityIntent}>
   146→          {rec.priority}
   147→        </Tag>
   148→      }
   149→    />
   150→  );
   151→}
   152→
   153→// =============================================================================
   154→// Popover Content
   155→// =============================================================================
   156→
   157→function BowWavePopoverContent({
   158→  state,
   159→  onRefresh,
   160→}: {
   161→  state: OverlaySliceState;
   162→  onRefresh: () => void;
   163→}) {
   164→  const riskDisplay = selectBowWaveRiskDisplay(state);
   165→  const peakPeriods = selectBowWavePeakPeriods(state);
   166→  const recommendations = selectBowWaveHighPriorityRecommendations(state);
   167→  const summary = selectBowWaveSummary(state);
   168→
   169→  if (state.bowWaveLoading) {
   170→    return (
   171→      <Menu>
   172→        <MenuItem
   173→          disabled
   174→          icon={<Spinner size={16} />}
   175→          text="Loading bow-wave analysis..."
   176→        />
   177→      </Menu>
   178→    );
   179→  }
   180→
   181→  if (state.bowWaveError) {
   182→    return (
   183→      <Menu>
   184→        <MenuItem
   185→          disabled
   186→          icon="error"
   187→          intent="danger"
   188→          text={`Error: ${state.bowWaveError}`}
   189→        />
   190→        <MenuDivider />
   191→        <MenuItem icon="refresh" text="Retry" onClick={onRefresh} />
   192→      </Menu>
   193→    );
   194→  }
   195→
   196→  if (!state.bowWaveData) {
   197→    return (
   198→      <Menu>
