/**
 * BowWaveIndicator Component
 *
 * Displays bow-wave risk status for maintenance clustering visualization.
 * Bow-wave occurs when PM work accumulates in later periods, causing
 * operational overload and potential service disruptions.
 *
 * This component shows:
 * - Current risk level (LOW/MEDIUM/HIGH/CRITICAL)
 * - Risk score (0-100%)
 * - Peak periods requiring attention
 * - Actionable recommendations
 *
 * @see specs/006-user-interface.md Section 6.5 - Overlay Panels
 * @see specs/004-domain-services.md Section 4.6 - Strategic Planner (bow-wave detection)
 */

import {
  Tag,
  Intent,
  Popover,
  Menu,
  MenuItem,
  MenuDivider,
  ProgressBar,
  Tooltip,
  Spinner,
  Classes,
} from '@blueprintjs/core';

import { useOverlay } from '../store';
import type { OverlaySliceState } from '../store/slices/overlay';
import {
  selectBowWaveRiskDisplay,
  selectBowWavePeakPeriods,
  selectBowWaveHighPriorityRecommendations,
  selectBowWaveSummary,
  loadBowWaveOverlayData,
  type BowWaveRiskLevel,
  type BowWavePeakPeriod,
  type BowWaveRecommendation,
} from '../store/slices/overlay';

// =============================================================================
// Types
// =============================================================================

interface BowWaveIndicatorProps {
  /** Show compact version for toolbar */
  compact?: boolean;
  /** Fleet ID to filter by */
  fleetId?: string;
  /** Plan ID to show specific plan's bow-wave analysis */
  planId?: string;
  /** Custom class name */
  className?: string;
}

// =============================================================================
// Color Mapping
// =============================================================================

const RISK_INTENT_MAP: Record<BowWaveRiskLevel, Intent> = {
  LOW: 'success',
  MEDIUM: 'warning',
  HIGH: 'warning',
  CRITICAL: 'danger',
};

const RISK_ICON_MAP: Record<BowWaveRiskLevel, 'tick-circle' | 'warning-sign' | 'error'> = {
  LOW: 'tick-circle',
  MEDIUM: 'warning-sign',
  HIGH: 'warning-sign',
  CRITICAL: 'error',
};

const RECOMMENDATION_ICON_MAP: Record<BowWaveRecommendation['type'], 'arrow-left' | 'arrow-right' | 'people' | 'horizontal-distribution'> = {
  ADVANCE_PM: 'arrow-left',
  DEFER_PM: 'arrow-right',
  ADD_CAPACITY: 'people',
  SPREAD_WORKLOAD: 'horizontal-distribution',
};

// =============================================================================
// Helper Components
// =============================================================================

function RiskProgressBar({
  riskScore,
  riskLevel,
}: {
  riskScore: number;
  riskLevel: BowWaveRiskLevel;
}) {
  const intent = RISK_INTENT_MAP[riskLevel];

  return (
    <div style={{ marginTop: 8 }}>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          marginBottom: 4,
          fontSize: 11,
        }}
      >
        <span className={Classes.TEXT_MUTED}>Risk Score</span>
        <span style={{ fontWeight: 500 }}>{Math.round(riskScore * 100)}%</span>
      </div>
      <ProgressBar
        value={riskScore}
        intent={intent}
        stripes={riskLevel === 'CRITICAL'}
        animate={riskLevel === 'CRITICAL'}
      />
    </div>
  );
}

function PeakPeriodItem({ period }: { period: BowWavePeakPeriod }) {
  const intent = RISK_INTENT_MAP[period.riskLevel];

  return (
    <MenuItem
      icon="calendar"
      text={`${period.startQuarter} - ${period.endQuarter}`}
      labelElement={
        <Tag minimal intent={intent}>
          {period.peakLoad} PMs/mo
        </Tag>
      }
    />
  );
}

function RecommendationItem({ rec }: { rec: BowWaveRecommendation }) {
  const priorityIntent: Intent =
    rec.priority === 'HIGH' ? 'danger' : rec.priority === 'MEDIUM' ? 'warning' : 'none';

  return (
    <MenuItem
      icon={RECOMMENDATION_ICON_MAP[rec.type]}
      text={rec.description}
      labelElement={
        <Tag minimal intent={priorityIntent}>
          {rec.priority}
        </Tag>
      }
    />
  );
}

// =============================================================================
// Popover Content
// =============================================================================

function BowWavePopoverContent({
  state,
  onRefresh,
}: {
  state: OverlaySliceState;
  onRefresh: () => void;
}) {
  const riskDisplay = selectBowWaveRiskDisplay(state);
  const peakPeriods = selectBowWavePeakPeriods(state);
  const recommendations = selectBowWaveHighPriorityRecommendations(state);
  const summary = selectBowWaveSummary(state);

  if (state.bowWaveLoading) {
    return (
      <Menu>
        <MenuItem
          disabled
          icon={<Spinner size={16} />}
          text="Loading bow-wave analysis..."
        />
      </Menu>
    );
  }

  if (state.bowWaveError) {
    return (
      <Menu>
        <MenuItem
          disabled
          icon="error"
          intent="danger"
          text={`Error: ${state.bowWaveError}`}
        />
        <MenuDivider />
        <MenuItem icon="refresh" text="Retry" onClick={onRefresh} />
      </Menu>
    );
  }

  if (!state.bowWaveData) {
    return (
      <Menu>
        <MenuItem
          disabled
          icon="info-sign"
          text="No bow-wave data available"
        />
        <MenuDivider />
        <MenuItem icon="refresh" text="Load Analysis" onClick={onRefresh} />
      </Menu>
    );
  }

  const { bowWaveData } = state;

  return (
    <Menu style={{ maxWidth: 400 }}>
      {/* Header with Risk Level */}
      <div style={{ padding: '8px 12px' }}>
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: 8,
          }}
        >
          <span style={{ fontWeight: 600, fontSize: 14 }}>{riskDisplay.label}</span>
          <Tag
            large
            intent={RISK_INTENT_MAP[riskDisplay.level]}
            icon={RISK_ICON_MAP[riskDisplay.level]}
          >
            {riskDisplay.level}
          </Tag>
        </div>

        <RiskProgressBar
          riskScore={bowWaveData.riskScore}
          riskLevel={riskDisplay.level}
        />
      </div>

      <MenuDivider />

      {/* Summary Stats */}
      {summary && (
        <>
          <div style={{ padding: '8px 12px' }}>
            <div className={Classes.TEXT_MUTED} style={{ fontSize: 11, marginBottom: 6 }}>
              Load Distribution
            </div>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: '1fr 1fr',
                gap: 8,
                fontSize: 12,
              }}
            >
              <div>
                <span className={Classes.TEXT_MUTED}>First Half: </span>
                <span style={{ fontWeight: 500 }}>{summary.firstHalfLoad} PMs</span>
              </div>
              <div>
                <span className={Classes.TEXT_MUTED}>Second Half: </span>
                <span style={{ fontWeight: 500 }}>{summary.secondHalfLoad} PMs</span>
              </div>
              <div>
                <span className={Classes.TEXT_MUTED}>Imbalance: </span>
                <span
                  style={{
                    fontWeight: 500,
                    color:
                      summary.loadImbalanceRatio > 1.5
                        ? '#DC2626'
                        : summary.loadImbalanceRatio > 1.2
                          ? '#F59E0B'
                          : '#10B981',
                  }}
                >
                  {summary.loadImbalanceRatio.toFixed(2)}x
                </span>
              </div>
              <div>
                <span className={Classes.TEXT_MUTED}>Total: </span>
                <span style={{ fontWeight: 500 }}>{summary.totalPms} PMs</span>
              </div>
            </div>
          </div>
          <MenuDivider />
        </>
      )}

      {/* Peak Periods */}
      {peakPeriods.length > 0 && (
        <>
          <MenuItem disabled text="Peak Periods" icon="timeline-events" />
          {peakPeriods.slice(0, 3).map((period, idx) => (
            <PeakPeriodItem key={idx} period={period} />
          ))}
          {peakPeriods.length > 3 && (
            <MenuItem
              disabled
              text={`... and ${peakPeriods.length - 3} more`}
              className={Classes.TEXT_MUTED}
            />
          )}
          <MenuDivider />
        </>
      )}

      {/* Recommendations */}
      {recommendations.length > 0 && (
        <>
          <MenuItem disabled text="Recommendations" icon="lightbulb" />
          {recommendations.slice(0, 3).map((rec, idx) => (
            <RecommendationItem key={idx} rec={rec} />
          ))}
          {recommendations.length > 3 && (
            <MenuItem
              disabled
              text={`... and ${recommendations.length - 3} more`}
              className={Classes.TEXT_MUTED}
            />
          )}
          <MenuDivider />
        </>
      )}

      {/* Actions */}
      <MenuItem icon="refresh" text="Refresh Analysis" onClick={onRefresh} />
      <MenuItem icon="chart" text="View Full Report" />
    </Menu>
  );
}

// =============================================================================
// Main Component
// =============================================================================

export function BowWaveIndicator({
  compact = false,
  fleetId,
  planId,
  className,
}: BowWaveIndicatorProps) {
  const { state: rawState, actions } = useOverlay();
  const state = rawState as unknown as OverlaySliceState;

  // Load data callback
  const loadData = () => {
    loadBowWaveOverlayData(
      {
        setBowWaveLoading: actions.setBowWaveLoading,
        setBowWaveData: actions.setBowWaveData,
        setBowWaveError: actions.setBowWaveError,
      },
      { fleetId, planId }
    );
  };

  // Auto-load data on initial render if never loaded
  // Check in render is safe because we're using slice state to track load status
  const shouldAutoLoad =
    state.bowWaveLastFetch === null &&
    !state.bowWaveLoading &&
    state.bowWaveData === null;

  if (shouldAutoLoad) {
    // Defer load to next microtask to avoid state updates during render
    Promise.resolve().then(loadData);
  }

  const riskDisplay = selectBowWaveRiskDisplay(state);
  const intent = RISK_INTENT_MAP[riskDisplay.level];
  const icon = RISK_ICON_MAP[riskDisplay.level];

  // Loading state
  if (state.bowWaveLoading && !state.bowWaveData) {
    return (
      <Tag minimal className={className}>
        <Spinner size={12} />
        <span style={{ marginLeft: 6 }}>Loading...</span>
      </Tag>
    );
  }

  // Compact version for toolbar
  if (compact) {
    return (
      <Popover
        content={<BowWavePopoverContent state={state} onRefresh={loadData} />}
        placement="bottom"
        interactionKind="hover"
        hoverOpenDelay={200}
      >
        <Tooltip content={riskDisplay.label} placement="bottom">
          <Tag
            intent={intent}
            icon={icon}
            interactive
            className={className}
            style={{ cursor: 'pointer' }}
          >
            {state.bowWaveData
              ? `${Math.round(state.bowWaveData.riskScore * 100)}%`
              : 'N/A'}
          </Tag>
        </Tooltip>
      </Popover>
    );
  }

  // Full version for status bar
  return (
    <Popover
      content={<BowWavePopoverContent state={state} onRefresh={loadData} />}
      placement="top"
      interactionKind="hover"
      hoverOpenDelay={200}
    >
      <Tag
        intent={intent}
        icon={icon}
        interactive
        className={className}
        style={{ cursor: 'pointer' }}
      >
        {riskDisplay.label}
        {state.bowWaveData && (
          <span style={{ marginLeft: 6, opacity: 0.8 }}>
            ({Math.round(state.bowWaveData.riskScore * 100)}%)
          </span>
        )}
      </Tag>
    </Popover>
  );
}

export default BowWaveIndicator;

