/**
 * Detail Card Overlay
 *
 * React DOM overlay for the detail view (zoom levels 16+).
 * Provides rich PM editing interfaces with:
 * - Full PM details in expandable cards
 * - Inline editing (date, depot, track, shift)
 * - Crew assignment display
 * - Material status with availability badges
 * - Compliance window timeline visualization
 * - Change history panel
 * - Real-time constraint validation feedback
 *
 * Uses BlueprintJS components for consistent UI.
 * State managed via @belt/tools (no React hooks).
 *
 * @see specs/006-user-interface.md Section 6.3.4, 6.3.5
 */

import { useRef } from 'react';
import {
  Card,
  Elevation,
  Tag,
  Intent,
  Button,
  ButtonGroup,
  Collapse,
  Icon,
  ProgressBar,
  Divider,
  HTMLTable,
  Tooltip,
  Position,
  Popover,
  Menu,
  MenuItem,
  MenuDivider,
} from '@blueprintjs/core';

import type { OperationalPmBlock, OperationalCanvasData, MaterialStatus } from './types';
import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';

// =============================================================================
// Types
// =============================================================================

export interface DetailPmBlock extends OperationalPmBlock {
  /** Change history for audit trail */
  changeHistory?: ChangeHistoryEntry[];
  /** Constraint validation results */
  constraintValidation?: DetailConstraintValidation;
  /** Assigned crew (if available) */
  assignedCrew?: CrewAssignment[];
}

export interface ChangeHistoryEntry {
  id: string;
  timestamp: string;
  changeType: 'CREATE' | 'MOVE' | 'REASSIGN' | 'LOCK' | 'UNLOCK' | 'STATUS_CHANGE';
  field?: string;
  oldValue?: string;
  newValue?: string;
  userId: string;
  userName: string;
  reason?: string;
}

export interface DetailConstraintValidation {
  isValid: boolean;
  violations: DetailConstraintViolation[];
  warnings: DetailConstraintWarning[];
}

export interface DetailConstraintViolation {
  type: 'HARD' | 'SOFT';
  constraint: string;
  message: string;
  canOverride: boolean;
}

export interface DetailConstraintWarning {
  type: string;
  message: string;
}

export interface CrewAssignment {
  crewId: string;
  crewName: string;
  role: string;
  shift: string;
}

export interface DetailCanvasData extends OperationalCanvasData {
  pmBlocks: DetailPmBlock[];
}

export interface DetailCardOverlayProps {
  data: DetailCanvasData | null;
  fromDate: Date;

/**
 * MMS Color System
 *
 * Defines the color palette for the MMS application.
 * Based on specs/006-user-interface.md Section 6.1.3.
 */

/** PM Status Colors */
export const PM_STATUS_COLORS = {
  scheduled: '#3B82F6',    // Blue
  inProgress: '#F59E0B',   // Amber
  completed: '#10B981',    // Green
  cancelled: '#6B7280',    // Gray
  deferred: '#8B5CF6',     // Purple
  overdue: '#EF4444',      // Red
} as const;

/** Constraint Indicator Colors */
export const CONSTRAINT_COLORS = {
  hardViolation: '#DC2626',    // Red-600
  softViolation: '#F59E0B',    // Amber-500
  approaching: '#FBBF24',      // Yellow-400
  ok: '#10B981',               // Green-500
} as const;

/** Drift Severity Colors */
export const DRIFT_COLORS = {
  critical: '#DC2626',     // Red
  warning: '#F59E0B',      // Amber
  ok: '#10B981',           // Green
} as const;

/** Man-hour Utilization Colors */
export const UTILIZATION_COLORS = {
  overloaded: '#DC2626',   // Red
  optimal: '#10B981',      // Green
  underutilized: '#3B82F6', // Blue
} as const;

/** Fleet Colors */
export const FLEET_COLORS = {
  KS: '#0EA5E9',           // Sky-500
  ALSTOM: '#8B5CF6',       // Violet-500
} as const;

/** Fitness Status Colors */
export const FITNESS_STATUS_COLORS = {
  FIT: '#10B981',          // Green
  RESTRICTED: '#F59E0B',   // Amber
  GROUNDED: '#EF4444',     // Red
} as const;

/** Material Availability Status Colors */
export const MATERIAL_STATUS_COLORS = {
  AVAILABLE: '#10B981',    // Green - Material in stock
  LOW_STOCK: '#F59E0B',    // Amber - Below minimum threshold
  UNAVAILABLE: '#EF4444',  // Red - Out of stock
  ARRIVING: '#3B82F6',     // Blue - On order, expected delivery
} as const;

/** Zoom Level Thresholds */
export const ZOOM_THRESHOLDS = {
  STRATEGIC: { min: 0, max: 4 },
  TACTICAL_WIDE: { min: 4, max: 8 },
  TACTICAL: { min: 8, max: 12 },
  OPERATIONAL: { min: 12, max: 16 },
  DETAIL: { min: 16, max: 20 },
} as const;

export type PmStatusColor = keyof typeof PM_STATUS_COLORS;
export type ConstraintColor = keyof typeof CONSTRAINT_COLORS;
export type DriftColor = keyof typeof DRIFT_COLORS;
export type UtilizationColor = keyof typeof UTILIZATION_COLORS;
export type FleetColor = keyof typeof FLEET_COLORS;
export type FitnessColor = keyof typeof FITNESS_STATUS_COLORS;
export type MaterialStatusColor = keyof typeof MATERIAL_STATUS_COLORS;

/**
 * MMS Components
 *
 * Central export for all React components.
 */

// Layout
export { Header, Toolbar, Sidebar, StatusBar } from './layout';

// Canvas
export { InfiniteCanvas } from './canvas';

// Theme
export * from './theme';

// Overlay Panels
export { ManHourOverlayPanel, DriftOverlayPanel, ScenarioComparisonView } from './overlay';
